const express = require('express');
const http = require('http');
const socketio = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = socketio(server);

const sessions = new Map();
const players = new Map();
const leaderboard = [];

function generateSessionToken() {
  return crypto.randomBytes(32).toString('hex');
}

function authenticatePlayer(username, password) {
  if (!username || username.length < 3) {
    return { success: false, message: 'Username must be at least 3 characters' };
  }
  
  const sessionToken = generateSessionToken();
  const playerId = crypto.createHash('md5').update(username).digest('hex');
  
  sessions.set(sessionToken, {
    playerId: playerId,
    username: username,
    createdAt: Date.now(),
    lastActivity: Date.now()
  });
  
  return {
    success: true,
    sessionToken: sessionToken,
    playerId: playerId,
    username: username
  };
}

function validateSession(sessionToken) {
  const session = sessions.get(sessionToken);
  if (!session) {
    return null;
  }
  
  const now = Date.now();
  if (now - session.lastActivity > 3600000) {
    sessions.delete(sessionToken);
    return null;
  }
  
  session.lastActivity = now;
  return session;
}

function updateLeaderboard(playerId, username, score) {
  const existingIndex = leaderboard.findIndex(entry => entry.playerId === playerId);
  
  if (existingIndex !== -1) {
    if (score > leaderboard[existingIndex].score) {
      leaderboard[existingIndex].score = score;
      leaderboard[existingIndex].username = username;
      leaderboard[existingIndex].updatedAt = Date.now();
    }
  } else {
    leaderboard.push({
      playerId: playerId,
      username: username,
      score: score,
      updatedAt: Date.now()
    });
  }
  
  leaderboard.sort((a, b) => b.score - a.score);
  
  if (leaderboard.length > 100) {
    leaderboard.splice(100);
  }
}

io.on('connection', (socket) => {
  console.log('New connection:', socket.id);
  
  let currentSession = null;
  
  socket.on('authenticate', (data) => {
    const { username, password } = data;
    const authResult = authenticatePlayer(username, password);
    
    if (authResult.success) {
      currentSession = sessions.get(authResult.sessionToken);
      
      players.set(socket.id, {
        playerId: authResult.playerId,
        username: authResult.username,
        sessionToken: authResult.sessionToken,
        socketId: socket.id,
        connectedAt: Date.now()
      });
      
      socket.emit('authenticated', {
        success: true,
        sessionToken: authResult.sessionToken,
        playerId: authResult.playerId,
        username: authResult.username
      });
      
      socket.emit('leaderboard', {
        leaderboard: leaderboard.slice(0, 10)
      });
      
      io.emit('playerJoined', {
        playerId: authResult.playerId,
        username: authResult.username
      });
      
      console.log('Player authenticated:', authResult.username);
    } else {
      socket.emit('authenticated', {
        success: false,
        message: authResult.message
      });
    }
  });
  
  socket.on('reconnect', (data) => {
    const { sessionToken } = data;
    const session = validateSession(sessionToken);
    
    if (session) {
      currentSession = session;
      
      players.set(socket.id, {
        playerId: session.playerId,
        username: session.username,
        sessionToken: sessionToken,
        socketId: socket.id,
        connectedAt: Date.now()
      });
      
      socket.emit('reconnected', {
        success: true,
        playerId: session.playerId,
        username: session.username
      });
      
      socket.emit('leaderboard', {
        leaderboard: leaderboard.slice(0, 10)
      });
      
      console.log('Player reconnected:', session.username);
    } else {
      socket.emit('reconnected', {
        success: false,
        message: 'Invalid or expired session'
      });
    }
  });
  
  socket.on('submitScore', (data) => {
    if (!currentSession) {
      socket.emit('scoreSubmitted', {
        success: false,
        message: 'Not authenticated'
      });
      return;
    }
    
    const { score } = data;
    
    if (typeof score !== 'number' || score < 0) {
      socket.emit('scoreSubmitted', {
        success: false,
        message: 'Invalid score'
      });
      return;
    }
    
    updateLeaderboard(currentSession.playerId, currentSession.username, score);
    
    socket.emit('scoreSubmitted', {
      success: true,
      score: score,
      message: 'Score submitted successfully'
    });
    
    io.emit('leaderboardUpdate', {
      leaderboard: leaderboard.slice(0, 10)
    });
    
    console.log(`Score submitted: ${currentSession.username} - ${score}`);
  });
  
  socket.on('playerMove', (data) => {
    if (!currentSession) {
      return;
    }
    
    socket.broadcast.emit('playerMoved', {
      playerId: currentSession.playerId,
      username: currentSession.username,
      position: data.position,
      direction: data.direction,
      timestamp: Date.now()
    });
  });
  
  socket.on('getLeaderboard', () => {
    socket.emit('leaderboard', {
      leaderboard: leaderboard.slice(0, 10)
    });
  });
  
  socket.on('getPlayerCount', () => {
    socket.emit('playerCount', {
      count: players.size
    });
  });
  
  socket.on('disconnect', () => {
    const player = players.get(socket.id);
    
    if (player) {
      io.emit('playerLeft', {
        playerId: player.playerId,
        username: player.username
      });
      
      players.delete(socket.id);
      console.log('Player disconnected:', player.username);
    }
    
    console.log('Connection closed:', socket.id);
  });
});

app.use(express.static('public'));

app.get('/api/leaderboard', (req, res) => {
  res.json({
    leaderboard: leaderboard.slice(0, 100)
  });
});

app.get('/api/stats', (req, res) => {
  res.json({
    activePlayers: players.size,
    totalSessions: sessions.size,
    leaderboardEntries: leaderboard.length
  });
});

const PORT = process.env.PORT || 3000;

server.listen(PORT, () => {
  console.log(`Game server running on port ${PORT}`);
});

setInterval(() => {
  const now = Date.now();
  for (const [token, session] of sessions.entries()) {
    if (now - session.lastActivity > 3600000) {
      sessions.delete(token);
    }
  }
}, 300000);